import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import api from '../utils/api';
import { useCart } from '../context/CartContext';

const FALLBACK_IMAGES = {
  Electronics: 'https://images.unsplash.com/photo-1498049794561-7780e7231661?w=400',
  Shoes: 'https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=400',
  Clothing: 'https://images.unsplash.com/photo-1523381210434-271e8be1f52b?w=400',
  Books: 'https://images.unsplash.com/photo-1544947950-fa07a98d237f?w=400',
  Beauty: 'https://images.unsplash.com/photo-1596462502278-27bfdc403348?w=400',
  Sports: 'https://images.unsplash.com/photo-1517649763962-0c623066013b?w=400',
  Home: 'https://images.unsplash.com/photo-1556909114-f6e7ad7d3136?w=400',
  default: 'https://images.unsplash.com/photo-1441986300917-64674bd600d8?w=400',
};

const BANNERS = [
  { title: '🔥 Big Electronics Sale', sub: 'Up to 40% off on top brands', btn: 'Shop Electronics →', color: 'linear-gradient(135deg, #1a1a2e, #0f3460)', category: 'Electronics' },
  { title: '👟 New Arrivals in Shoes', sub: 'Step into style this season', btn: 'Shop Shoes →', color: 'linear-gradient(135deg, #e94560, #c62a47)', category: 'Shoes' },
  { title: '📚 Books Under ₹299', sub: 'Expand your mind, not your budget', btn: 'Shop Books →', color: 'linear-gradient(135deg, #0f3460, #533483)', category: 'Books' },
];

const CATEGORIES = [
  { name: 'Electronics', icon: '📱', color: '#e3f2fd' },
  { name: 'Clothing', icon: '👕', color: '#fce4ec' },
  { name: 'Shoes', icon: '👟', color: '#e8f5e9' },
  { name: 'Books', icon: '📚', color: '#fff3e0' },
  { name: 'Beauty', icon: '💄', color: '#f3e5f5' },
  { name: 'Sports', icon: '⚽', color: '#e0f7fa' },
  { name: 'Home', icon: '🏡', color: '#fbe9e7' },
];

const Home = ({ selectedCategory, searchQuery }) => {
  const [products, setProducts] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [loading, setLoading] = useState(true);
  const [sort, setSort] = useState('default');
  const [bannerIdx, setBannerIdx] = useState(0);
  const [hoveredId, setHoveredId] = useState(null);
  const { addToCart } = useCart();

  useEffect(() => {
    api.get('/products')
      .then(res => { setProducts(res.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  useEffect(() => {
    const timer = setInterval(() => setBannerIdx(i => (i + 1) % BANNERS.length), 3000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    let result = [...products];
    if (selectedCategory && selectedCategory !== 'All') {
      result = result.filter(p => p.category === selectedCategory);
    }
    if (searchQuery) {
      result = result.filter(p =>
        p.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        p.category.toLowerCase().includes(searchQuery.toLowerCase())
      );
    }
    if (sort === 'low') result.sort((a, b) => a.price - b.price);
    if (sort === 'high') result.sort((a, b) => b.price - a.price);
    if (sort === 'name') result.sort((a, b) => a.name.localeCompare(b.name));
    setFiltered(result);
  }, [searchQuery, selectedCategory, sort, products]);

  const getImage = (p) => {
    if (p.image && p.image.startsWith('http')) return p.image;
    return FALLBACK_IMAGES[p.category] || FALLBACK_IMAGES.default;
  };

  const renderStars = (rating) => '★'.repeat(Math.round(rating || 4)) + '☆'.repeat(5 - Math.round(rating || 4));

  const banner = BANNERS[bannerIdx];
  const featuredProducts = products.filter(p => p.category === 'Electronics').slice(0, 4);
  const deals = products.filter(p => p.price < 2000).slice(0, 4);

  if (loading) return (
    <div style={styles.loadingWrapper}>
      <div style={styles.spinner}></div>
      <p>Loading products...</p>
    </div>
  );

  const showingSections = !selectedCategory || selectedCategory === 'All';

  return (
    <div style={styles.page}>

      {showingSections && !searchQuery && (
        <>
          {/* Hero Banner */}
          <div style={{ ...styles.hero, background: banner.color }}>
            <div style={styles.heroContent}>
              <h1 style={styles.heroTitle}>{banner.title}</h1>
              <p style={styles.heroSub}>{banner.sub}</p>
              <button style={styles.heroBtn}>{banner.btn}</button>
            </div>
            <div style={styles.bannerDots}>
              {BANNERS.map((_, i) => (
                <div key={i} onClick={() => setBannerIdx(i)}
                  style={i === bannerIdx ? styles.dotActive : styles.dot} />
              ))}
            </div>
          </div>

          {/* Category Pills */}
          <div style={styles.catSection}>
            <h2 style={styles.sectionTitle}>🛍️ Shop by Category</h2>
            <div style={styles.catGrid}>
              {CATEGORIES.map(c => (
                <div key={c.name} style={{ ...styles.catCard, background: c.color }}>
                  <span style={styles.catIcon}>{c.icon}</span>
                  <span style={styles.catName}>{c.name}</span>
                </div>
              ))}
            </div>
          </div>

          {/* Featured Electronics */}
          {featuredProducts.length > 0 && (
            <div style={styles.section}>
              <div style={styles.sectionHeader}>
                <h2 style={styles.sectionTitle}>⚡ Featured Electronics</h2>
                <span style={styles.viewAll}>View All →</span>
              </div>
              <div style={styles.featuredGrid}>
                {featuredProducts.map(p => (
                  <ProductCard key={p._id} p={p} getImage={getImage} renderStars={renderStars}
                    addToCart={addToCart} hoveredId={hoveredId} setHoveredId={setHoveredId} />
                ))}
              </div>
            </div>
          )}

          {/* Deals Under ₹2000 */}
          {deals.length > 0 && (
            <div style={{ ...styles.section, background: '#fff9f0' }}>
              <div style={styles.sectionHeader}>
                <h2 style={styles.sectionTitle}>🏷️ Deals Under ₹2000</h2>
                <span style={styles.viewAll}>View All →</span>
              </div>
              <div style={styles.featuredGrid}>
                {deals.map(p => (
                  <ProductCard key={p._id} p={p} getImage={getImage} renderStars={renderStars}
                    addToCart={addToCart} hoveredId={hoveredId} setHoveredId={setHoveredId} />
                ))}
              </div>
            </div>
          )}

          {/* Promo Banners */}
          <div style={styles.promoBanners}>
            <div style={{ ...styles.promoBanner, background: 'linear-gradient(135deg, #e94560, #c62a47)' }}>
              <h3 style={styles.promoTitle}>💄 Beauty Sale</h3>
              <p style={styles.promoSub}>Up to 30% off on beauty products</p>
              <button style={styles.promoBtn}>Shop Now →</button>
            </div>
            <div style={{ ...styles.promoBanner, background: 'linear-gradient(135deg, #0f3460, #533483)' }}>
              <h3 style={styles.promoTitle}>⚽ Sports Gear</h3>
              <p style={styles.promoSub}>Best deals on sports equipment</p>
              <button style={styles.promoBtn}>Shop Now →</button>
            </div>
            <div style={{ ...styles.promoBanner, background: 'linear-gradient(135deg, #1a1a2e, #16213e)' }}>
              <h3 style={styles.promoTitle}>📚 Books Festival</h3>
              <p style={styles.promoSub}>Top bestsellers starting ₹199</p>
              <button style={styles.promoBtn}>Shop Now →</button>
            </div>
          </div>
        </>
      )}

      {/* All Products */}
      <div style={styles.section}>
        <div style={styles.sectionHeader}>
          <h2 style={styles.sectionTitle}>
            {selectedCategory && selectedCategory !== 'All' ? '📁 ' + selectedCategory : '🏠 All Products'}
            <span style={styles.countBadge}>{filtered.length} items</span>
          </h2>
          <select value={sort} onChange={e => setSort(e.target.value)} style={styles.select}>
            <option value="default">Sort: Featured</option>
            <option value="low">Price: Low to High</option>
            <option value="high">Price: High to Low</option>
            <option value="name">Name: A-Z</option>
          </select>
        </div>

        {filtered.length === 0 ? (
          <div style={styles.empty}>
            <p style={{ fontSize: '48px' }}>😕</p>
            <p>No products found.</p>
          </div>
        ) : (
          <div style={styles.grid}>
            {filtered.map(p => (
              <ProductCard key={p._id} p={p} getImage={getImage} renderStars={renderStars}
                addToCart={addToCart} hoveredId={hoveredId} setHoveredId={setHoveredId} />
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

const ProductCard = ({ p, getImage, renderStars, addToCart, hoveredId, setHoveredId }) => (
  <div
    style={{ ...styles.card, transform: hoveredId === p._id ? 'translateY(-4px)' : 'none', boxShadow: hoveredId === p._id ? '0 8px 24px rgba(0,0,0,0.15)' : '0 2px 8px rgba(0,0,0,0.07)' }}
    onMouseEnter={() => setHoveredId(p._id)}
    onMouseLeave={() => setHoveredId(null)}
  >
    <Link to={'/product/' + p._id}>
      <div style={styles.imgWrapper}>
        <img src={getImage(p)} alt={p.name} style={styles.img}
          onError={e => { e.target.src = 'https://images.unsplash.com/photo-1441986300917-64674bd600d8?w=400'; }} />
        {p.stock < 10 && p.stock > 0 && <span style={styles.lowStock}>Only {p.stock} left!</span>}
        {p.stock === 0 && <span style={styles.outOfStock}>Out of Stock</span>}
        <span style={styles.discountBadge}>17% OFF</span>
      </div>
    </Link>
    <div style={styles.cardBody}>
      <p style={styles.cardCategory}>{p.category}</p>
      <Link to={'/product/' + p._id} style={styles.cardTitle}>{p.name}</Link>
      <div style={styles.stars}>
        <span style={styles.starText}>{renderStars(p.rating)}</span>
        <span style={styles.reviewCount}>({p.numReviews || 0})</span>
      </div>
      <div style={styles.priceRow}>
        <span style={styles.price}>₹{p.price.toLocaleString()}</span>
        <span style={styles.originalPrice}>₹{(p.price * 1.2).toFixed(0)}</span>
      </div>
      <p style={styles.delivery}>🚚 FREE Delivery</p>
      <button onClick={() => addToCart(p)} disabled={p.stock === 0}
        style={p.stock === 0 ? styles.disabledBtn : styles.addBtn}>
        {p.stock === 0 ? 'Out of Stock' : '🛒 Add to Cart'}
      </button>
    </div>
  </div>
);

const styles = {
